echo "OS: $(lsb_release -ds 2>/dev/null || cat /etc/os-release | grep PRETTY_NAME | cut -d= -f2 | tr -d '\"')" && echo "Kernel: $(uname -r)" && echo "CUDA: $(nvcc --version | grep release | awk '{print $6}' | cut -d',' -f1 2>/dev/null || echo 'N/A')" && echo "Container Toolkit: $(dpkg -l | grep nvidia-container-toolkit | awk '{print $3}' 2>/dev/null || echo 'N/A')" && echo "CPU: $(lscpu | grep 'Model name' | cut -d: -f2 | xargs)" && echo "Cores: $(lscpu | grep '^CPU(s):' | awk '{print $2}')" && echo "Threads: $(lscpu | grep 'Thread(s) per core' | awk '{print $4}')" && echo "Memory: $(free -h | awk '/Mem:/ {print $2}')"